  const dependencies = Object.keys(packageData.dependencies);
  const allowlistedDependencies = ['express', 'lodash', 'moment'];

  // Keep secrets, tokens, and sensitive data out of plaintext storage and logs
  const lockFileContent = JSON.stringify({
    name: packageData.name,
    version: packageData.version,
    dependencies: dependencies.reduce((acc, dependency) => {
      if (allowlistedDependencies.includes(dependency)) {
        acc[dependency] = packageData.dependencies[dependency];
      }
      return acc;
    }, {}),
  });

  fs.writeFileSync(lockFilePath, lockFileContent);
